function extractClaudeBlog() {
  const main = document.querySelector('main') || document.body;
  const clone = main.cloneNode(true);
  const selectors = ['nav', 'footer', 'script', 'style', '.nav_dropdown_wrap', '.w-nav', '.footer'];
  selectors.forEach(s => clone.querySelectorAll(s).forEach(el => el.remove()));

  let md = "# " + (document.querySelector('h1')?.innerText || document.title) + "\n\n";
  const content = clone.querySelector('.u-rich-text-blog') || clone;

  function walk(node) {
    if (node.nodeType === 3) return node.textContent;
    let res = "";
    const tag = node.tagName;
    if (/^H[1-6]$/.test(tag)) res += "\n" + "#".repeat(tag[1]) + " " + node.innerText + "\n";
    else if (tag === 'P') res += node.innerText + "\n\n";
    else if (tag === 'PRE' || tag === 'CODE') res += "\n```\n" + node.innerText + "\n```\n\n";
    else if (tag === 'LI') res += "* " + node.innerText + "\n";
    else node.childNodes.forEach(c => res += walk(c));
    return res;
  }

  return md + walk(content).replace(/\n{3,}/g, '\n\n');
}
extractClaudeBlog();
